proof:
by_contra h;
have h_bounded : ∃ C > 0, ∀ t ∈ Set.Ici (1 : ℝ), ‖Φ₆ r t‖ ≤ C * Real.exp (-2 * Real.pi * t) * Real.exp (-Real.pi * r * t) := by
  have := MagicFunction.a.IntegralEstimates.I₆.I₆'_bounding_aux_2 r;
  convert this using 6 ; unfold MagicFunction.a.IntegralEstimates.I₆.g ; ring ; norm_num [ Complex.exp_re, Complex.exp_im, Real.sin, Real.cos, Real.pi_pos.le ] ; ring;
  unfold Φ₆; norm_num [ Complex.norm_exp ] ; ring;
  unfold MagicFunction.a.ComplexIntegrands.Φ₆' MagicFunction.Parametrisations.z₆'; norm_num [ Complex.norm_exp ] ; ring;
  unfold IciExtend z₆; norm_num [ Complex.exp_re, Complex.exp_im, Real.sin, Real.cos, Real.pi_pos.le ] ; ring;
  unfold projIci; aesop;
obtain ⟨ C, hC₀, hC ⟩ := h_bounded;
refine' h _;
refine' lt_of_le_of_lt ( MeasureTheory.lintegral_mono_ae _ ) _;
use fun t => ENNReal.ofReal ( C * Real.exp ( -2 * Real.pi * t ) * Real.exp ( -Real.pi * r * t ) );
· filter_upwards [ MeasureTheory.ae_restrict_mem measurableSet_Ici ] with t ht using by simpa [ ENNReal.ofReal ] using ENNReal.ofReal_le_ofReal ( hC t ht ) ;
· have h_exp_integrable : MeasureTheory.IntegrableOn (fun t => C * Real.exp (-2 * Real.pi * t) * Real.exp (-Real.pi * r * t)) (Set.Ici (1 : ℝ)) := by
    exact MagicFunction.a.IntegralEstimates.I₆.Bound_integrableOn r C hr.le
  convert h_exp_integrable.lintegral_lt_top using 1

